import{_ as a,c as t,o as i,a2 as n}from"./chunks/framework.CIiVzG-O.js";const g=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1776396452000}'),r={name:"guide/introduction.md"};function o(s,e,l,d,u,h){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="about-nicasa" tabindex="-1">About Nicasa <a class="header-anchor" href="#about-nicasa" aria-label="Permalink to &quot;About Nicasa&quot;">​</a></h2><p>Nicasa is a modern desktop image viewer and screenshot tool designed for speed, simplicity, and powerful editing capabilities. Built exclusively for macOS, Nicasa brings a smooth, modern image-viewing experience to your desktop.</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><h3 id="🖼️-better-way-to-view-images" tabindex="-1">🖼️ <strong>Better Way to View Images</strong> <a class="header-anchor" href="#🖼️-better-way-to-view-images" aria-label="Permalink to &quot;🖼️ **Better Way to View Images**&quot;">​</a></h3><p>Open images instantly with a clean and focused interface. No distractions, no clutter — just your content, beautifully presented the moment you open it.</p><h3 id="📸-screenshot-capture" tabindex="-1">📸 <strong>Screenshot &amp; Capture</strong> <a class="header-anchor" href="#📸-screenshot-capture" aria-label="Permalink to &quot;📸 **Screenshot &amp; Capture**&quot;">​</a></h3><p>Capture any part of your screen in seconds. With fast, precise screenshot tools built right into Nicasa, saving and sharing visual ideas has never been easier.</p><h3 id="🤖-ai-image-editor" tabindex="-1">🤖 <strong>AI Image Editor</strong> <a class="header-anchor" href="#🤖-ai-image-editor" aria-label="Permalink to &quot;🤖 **AI Image Editor**&quot;">​</a></h3><p>Enhance and refine your images with powerful AI tools. From quick adjustments to intelligent editing, Nicasa helps you transform images effortlessly.</p><h3 id="🔍-transparent-overlay-mode" tabindex="-1">🔍 <strong>Transparent Overlay Mode</strong> <a class="header-anchor" href="#🔍-transparent-overlay-mode" aria-label="Permalink to &quot;🔍 **Transparent Overlay Mode**&quot;">​</a></h3><p>A powerful tool for designers and artists: pin an image above all windows with adjustable transparency — perfect for tracing, reference work, and UI comparison.</p><h3 id="🌐-chrome-extension-integration" tabindex="-1">🌐 <strong>Chrome Extension Integration</strong> <a class="header-anchor" href="#🌐-chrome-extension-integration" aria-label="Permalink to &quot;🌐 **Chrome Extension Integration**&quot;">​</a></h3><p>Seamlessly connect with the Nicasa Chrome extension to view all images on any website in one place. Instantly extract, browse, and open images directly in Nicasa for a faster and more immersive viewing experience.</p><h3 id="🎨-smooth-intuitive-design" tabindex="-1">🎨 <strong>Smooth &amp; Intuitive Design</strong> <a class="header-anchor" href="#🎨-smooth-intuitive-design" aria-label="Permalink to &quot;🎨 **Smooth &amp; Intuitive Design**&quot;">​</a></h3><p>Powered by next-generation technology, Nicasa delivers a polished experience with fluid transitions, crisp rendering, and thoughtful interaction design.</p><h2 id="system-requirements" tabindex="-1">System Requirements <a class="header-anchor" href="#system-requirements" aria-label="Permalink to &quot;System Requirements&quot;">​</a></h2><ul><li><strong>Operating System</strong>: macOS 10.13 or later</li><li><strong>Memory</strong>: 4GB RAM minimum, 8GB recommended</li><li><strong>Storage</strong>: 54.5 MB for installation</li><li><strong>Display</strong>: 1280x720 minimum resolution</li></ul><h2 id="supported-languages" tabindex="-1">Supported Languages <a class="header-anchor" href="#supported-languages" aria-label="Permalink to &quot;Supported Languages&quot;">​</a></h2><p>Nicasa supports a wide range of languages, including English, Chinese (Simplified), Chinese (Traditional), Japanese, French, Korean, German, Spanish, Italian, Vietnamese, Thai, Hindi, Turkish, Russian, Portuguese, Dutch, German (Switzerland), Finnish, Malay, Greek, Norwegian, Indonesian, Hungarian, Danish, and Ukrainian.</p><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>If you&#39;re new to Nicasa, start with the <a href="/guide/installation.html">Installation Guide</a> to get the application running on your Mac.</p>',22)])])}const m=a(r,[["render",o]]);export{g as __pageData,m as default};
